app.post('/api/invoices/scan', authWithRestaurant, async (req, res) => {
  try {
    if (!process.env.ANTHROPIC_API_KEY) return res.status(503).json({ error: 'Service IA non configurÃ©. Ajoutez ANTHROPIC_API_KEY.' });
